import React, { useState, useEffect } from "react";
import { api } from "../api";
import Header from "../components/Header";

export default function Accounts() {
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function fetchAccounts() {
      try {
        const token = localStorage.getItem("token");
        const res = await api.get("/accounts", {
          headers: { Authorization: `Bearer ${token}` },
        });
        setTransactions(res.data.transactions);
        setError(null);
      } catch (err) {
        setError("Failed to load accounts");
        console.error(err);
      } finally {
        setLoading(false);
      }
    }
    fetchAccounts();
  }, []);

  if (loading) return <div>Loading account data...</div>;
  if (error) return <div style={{ color: "red" }}>{error}</div>;

  return (
    <>
      <Header />
      <div style={{ maxWidth: 800, margin: "auto", padding: 20 }}>
        <h2>Account Transactions</h2>
        {transactions.length === 0 ? (
          <p>No transactions found.</p>
        ) : (
          <ul>
            {transactions.map((txn) => (
              <li key={txn._id} style={{ marginBottom: 10 }}>
                <div>Name: {txn.name}</div>
                <div>Amount: ₹{txn.amount}</div>
                <div>Type: {txn.interestType}</div>
                <div>Date: {new Date(txn.date).toLocaleDateString()}</div>
                <div>Status: {txn.status}</div>
              </li>
            ))}
          </ul>
        )}
      </div>
    </>
  );
}
